function extractAdvisoriesFromHTML(html, inputPath) {
    const advisories = [];
    const trRegex = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
    let trMatch;
    let rowIndex = 0;
    const versionMatch = inputPath.match(/alas(\d+)/i);
    const version = versionMatch ? versionMatch[1] : "";

    while ((trMatch = trRegex.exec(html)) !== null) {
        if (rowIndex === 0) {
            rowIndex++;
            continue;
        }

        const trContent = trMatch[1];
        const tdRegex = /<td[^>]*>([\s\S]*?)<\/td>/gi;
        const tds = [];
        let tdMatch;

        while ((tdMatch = tdRegex.exec(trContent)) !== null) {
            let tdText = tdMatch[1].replace(/<[^>]+>/g, "").trim();
            tds.push(tdText);
        }

        const alasIdMatch = trContent.match(/<td[^>]*>\s*<a[^>]*href=['"]([^'"]+)['"][^>]*>([^<]+)<\/a>/i);
        let alas_url = null;
        let alas_id = null;

        if (alasIdMatch) {
            alas_url = alasIdMatch[1];
            alas_id = alasIdMatch[2];
        }

        const cveTdMatch = trContent.match(/<td[^>]*>([\s\S]*?)<\/td>/gi);
        let cves = [];

        if (cveTdMatch && cveTdMatch[5]) {
            const cveLinks = [
                ...cveTdMatch[5].matchAll(/<a[^>]*href=['"]([^'"]+)['"][^>]*>([^<]+)<\/a>/gi)
            ];

            cves = cveLinks.map(m => ({
                cve_id: m[2],
                cve_url: m[1]
            }));
        }

        advisories.push({
            date_released: tds[0] || null,
            date_updated: tds[1] || null,
            alas_id: alas_id,
            alas_url: alas_url,
            severity: tds[3] || null,
            package: tds[4] || null,
            cves: cves,
            version: version
        });
    }

    return advisories;
};

$advisories = extractAdvisoriesFromHTML($Fetch_Advisory.result, $ForEach_end_points.item);
