function extractIssueCorrection(html) {
    const divMatch = html.match(/<div id=["']issue_correction["'][^>]*>([\s\S]*?)<\/div>/i);

    if (!divMatch)
        return null;

    const divContent = divMatch[1];
    const commandMatch = divContent.match(/(?:dnf|yum|microdnf|dnf5) update [^<\n\r]+/i);
    return commandMatch ? commandMatch[0].trim() : null;
};

$issueCorrection = extractIssueCorrection($Get_IssueCorrection.result)

