function generateUUID() {
    return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, function(c) {
        let r = Math.random() * 16 | 0, v = c === "x" ? r : (r & 0x3 | 0x8);
        return v.toString(16);
    });
};

function transformAdvisory(advisory, issueCorrectionText, awsAdvisoryBaseUrl, endpoint) {
    const version = advisory.version;
    const isAlas2023 = version === "2023";
    let advisory_payload = {};

    if (isAlas2023 && issueCorrectionText) {
        advisory_payload = {
            metadata: {
                issue_correction: issueCorrectionText
            }
        };
    }

    let advisory_url = `${awsAdvisoryBaseUrl}/${advisory.alas_url}`;
    advisory_payload["advisory_url"] = advisory_url;

    if (!advisory.cves || advisory.cves.length === 0) {
        return [{
            id: generateUUID(),
            key: `CVE-unknown_OS_amazonlinux_${version}`,
            cve: null,
            advisory_recommender: "amazonlinux",
            advisory: advisory.alas_id,
            product: "amazon linux",
            os_version: version,
            advisory_payload: JSON.stringify(advisory_payload),
            severity: advisory.severity,
            cpe: ""
        }];
    }

    return advisory.cves.map(cveObj => ({
        id: generateUUID(),
        key: `${cveObj.cve_id}_OS_amazonlinux_${version}`,
        cve: cveObj.cve_id,
        advisory_recommender: "amazonlinux",
        advisory: advisory.alas_id,
        product: "amazon linux",
        os_version: version,
        advisory_payload: JSON.stringify(advisory_payload),
        severity: advisory.severity,
        cpe: ""
    }));
}

